import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;

public class TransactionProcessor {
    public static boolean processTransaction(String accountNumber, double amount) throws Exception {
        // Load the JDBC driver for MySQL
        Class.forName("com.mysql.cj.jdbc.Driver");

        try (Connection conn = DriverManager.getConnection("jdbc:mysql://localhost:3306/banking", "username", "password")) {
            String query = "SELECT balance FROM accounts WHERE account_number = ?";

            try (PreparedStatement pstmt = conn.prepareStatement(query)) {
                pstmt.setString(1, accountNumber);
                try (ResultSet rs = pstmt.executeQuery()) {
                    if (!rs.next()) {
                        return false; // Account not found
                    }

                    double currentBalance = rs.getDouble("balance");

                    if (amount <= 0) {
                        return false; // Invalid transaction amount
                    }

                    if (currentBalance < amount) {
                        return false; // Insufficient funds
                    }

                    query = "UPDATE accounts SET balance = balance - ? WHERE account_number = ?";
                    pstmt.setDouble(1, amount);
                    pstmt.setString(2, accountNumber);

                    int rowsAffected = pstmt.executeUpdate();

                    if (rowsAffected == 0) {
                        return false; // Update failed
                    }
                }
            }
        } catch (Exception e) {
            throw new Exception("Error processing transaction: " + e.getMessage());
        }

        return true;
    }
}